def safe_float(value, default=np.nan) -> float:
    try:
        if value is None or value == "":
            return default
        return float(value)
    except Exception:
        return default


def safe_series(frame: pd.DataFrame, col: str, default: float = 0.0) -> pd.Series:
    if frame is not None and col in frame.columns:
        return pd.to_numeric(frame[col], errors="coerce").fillna(default)
    if frame is None:
        return pd.Series(dtype=float)
    return pd.Series(default, index=frame.index, dtype=float)


def discover_sector_csvs(root_dir: str = SECTORS_DIR) -> List[str]:
    if not os.path.isdir(root_dir):
        return []
    paths = []
    for dirpath, _, filenames in os.walk(root_dir):
        for fname in filenames:
            if fname.lower().endswith(".csv"):
                paths.append(os.path.join(dirpath, fname))
    return sorted(set(paths))


def load_fno_symbols_from_sectors(root_dir: str = SECTORS_DIR) -> List[str]:
    symbols = set()
    for path in discover_sector_csvs(root_dir):
        try:
            df = pd.read_csv(path)
        except Exception:
            continue
        lowered = {str(c).strip().lower(): c for c in df.columns}
        symbol_col = next(
            (lowered[k] for k in ["symbol", "symbols", "ticker", "tradingsymbol"] if k in lowered),
            None,
        )
        if symbol_col is None:
            continue
        for raw in df[symbol_col].dropna().astype(str):
            sym = raw.strip().upper()
            if sym and sym not in {"NAN", "NONE"}:
                symbols.add(sym)
    return sorted(symbols)


def format_eq_symbol(symbol: str) -> str:
    symbol = str(symbol).strip().upper()
    if symbol.startswith("NSE:"):
        return symbol if symbol.endswith("-EQ") else f"{symbol}-EQ"
    return f"NSE:{symbol}-EQ"


def get_history(symbol: str, resolution: str, days_back: int) -> pd.DataFrame:
    if fyers is None:
        return pd.DataFrame()
    now   = datetime.now()
    start = now - timedelta(days=days_back)
    payload = {
        "symbol": symbol, "resolution": resolution, "date_format": "1",
        "range_from": start.strftime("%Y-%m-%d"),
        "range_to":   now.strftime("%Y-%m-%d"),
        "cont_flag":  "1",
    }
    try:
        res = fyers.history(data=payload)
    except Exception:
        return pd.DataFrame()
    candles = (res or {}).get("candles", [])
    if not candles:
        return pd.DataFrame()
    df = pd.DataFrame(candles, columns=["timestamp", "open", "high", "low", "close", "volume"])
    df["timestamp"] = (
        pd.to_datetime(df["timestamp"], unit="s", utc=True)
        .dt.tz_convert("Asia/Kolkata")
        .dt.tz_localize(None)
    )
    return (
        df.sort_values("timestamp")
        .drop_duplicates(subset=["timestamp"], keep="last")
        .reset_index(drop=True)
    )


def nearest_step(value: float) -> int:
    val = abs(safe_float(value, 0))
    if val >= 20000: return 100
    if val >= 10000: return 50
    if val >= 2000:  return 20
    if val >= 500:   return 10
    if val >= 100:   return 5
    return 1


def today_session_df(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    d = df.copy().sort_values("timestamp").reset_index(drop=True)
    d["timestamp"] = pd.to_datetime(d["timestamp"])
    last_day = d["timestamp"].dt.date.max()
    start_ts = pd.Timestamp.combine(pd.Timestamp(last_day).date(), dtime(9, 15))
    return d[(d["timestamp"].dt.date == last_day) & (d["timestamp"] >= start_ts)].copy().reset_index(drop=True)


def session_price_move_pct(df: pd.DataFrame) -> float:
    d = today_session_df(df)
    if d.empty or len(d) < 2 or "close" not in d.columns:
        return np.nan
    close = pd.to_numeric(d["close"], errors="coerce")
    first_close = safe_float(close.iloc[0], np.nan)
    last_close = safe_float(close.iloc[-1], np.nan)
    if pd.isna(first_close) or first_close == 0 or pd.isna(last_close):
        return np.nan
    return round((last_close - first_close) / first_close * 100.0, 2)


